Avec Animated : on utilise useRef(new Animated.Value(1)), puis Animated.spring(...).start(). Avec Reanimated 2 : on utilise useSharedValue(1) et un style animé via useAnimatedStyle, puis on modifie la shared value dans un gesture handler ou une fonction. Le code Reanimated 2 sépare clairement la valeur partagée, le style réactif, et l’animation via withSpring ou withTiming. Exemple Reanimated :

```js
const scale = useSharedValue(1);
const animatedStyle = useAnimatedStyle(() => ({ transform: [{ scale: scale.value }] }));
const handlePress = () => { scale.value = withSpring(1.2, { damping: 3 }, () => { scale.value = withSpring(1); }); };
```
La grande différence : la logique d’animation est déportée sur le thread UI et la mise à jour du style est automatique.

```jsx
import React from 'react';
import { View, StyleSheet } from 'react-native';
import { PanGestureHandler } from 'react-native-gesture-handler';
import Animated, { useSharedValue, useAnimatedStyle, useAnimatedGestureHandler, withDecay } from 'react-native-reanimated';

const DraggableCircle = () => {
  const translateX = useSharedValue(0);
  const translateY = useSharedValue(0);

  const gestureHandler = useAnimatedGestureHandler({
    onStart: (_, ctx) => {
      ctx.startX = translateX.value;
      ctx.startY = translateY.value;
    },
    onUpdate: (event, ctx) => {
      translateX.value = ctx.startX + event.translationX;
      translateY.value = ctx.startY + event.translationY;
    },
    onEnd: (event) => {
      translateX.value = withDecay({ velocity: event.velocityX, deceleration: 0.997 });
      translateY.value = withDecay({ velocity: event.velocityY, deceleration: 0.997 });
    },
  });

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ translateX: translateX.value }, { translateY: translateY.value }],
  }));

  return (
    <View style={styles.container}>
      <PanGestureHandler onGestureEvent={gestureHandler}>
        <Animated.View style={[styles.circle, animatedStyle]} />
      </PanGestureHandler>
    </View>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1, justifyContent: 'center', alignItems: 'center' },
  circle: { width: 80, height: 80, borderRadius: 40, backgroundColor: '#3b82f6' },
});

export default DraggableCircle;
```

```jsx
import React, { useEffect } from 'react';
import { View, Text } from 'react-native';
import Animated, { useSharedValue, useAnimatedStyle, withTiming, withDelay, withSequence } from 'react-native-reanimated';

const SplashAnimation = () => {
  const logoOpacity = useSharedValue(0);
  const logoTranslateY = useSharedValue(-50);
  const textTranslateX = useSharedValue(100);

  useEffect(() => {
    logoOpacity.value = withTiming(1, { duration: 800 });
    logoTranslateY.value = withTiming(0, { duration: 800 });
    // texte retardé de 300ms après début
    textTranslateX.value = withDelay(1100, withTiming(0, { duration: 600 }));
  }, []);

  const logoStyle = useAnimatedStyle(() => ({
    opacity: logoOpacity.value,
    transform: [{ translateY: logoTranslateY.value }],
  }));
  const textStyle = useAnimatedStyle(() => ({
    transform: [{ translateX: textTranslateX.value }],
  }));

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Animated.Image source={require('./logo.png')} style={[logoStyle, { width: 100, height: 100 }]} />
      <Animated.Text style={[textStyle, { fontSize: 20, marginTop: 20 }]}>Bienvenue !</Animated.Text>
    </View>
  );
};
```
